const cfg = $('Config').first().json;
const PB_URL = (cfg.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token; const pbH = { Authorization: token };
const id = (($('Webhook').first().json.body) || {}).id;
const discover = $('Discover').first().json;        // slow call already done by the HTTP node
const method = discover.extraction_method || '';

let gate = 'auto_safe';
try { const s = await this.helpers.httpRequest({ method:'GET', url: PB_URL+'/api/collections/settings/records', qs:{ filter:"(key='extraction_gate')", perPage:1 }, headers:pbH, json:true }); if (s.items && s.items[0]) gate = s.items[0].value || 'auto_safe'; } catch(e) {}
const fed = await this.helpers.httpRequest({ method:'GET', url: PB_URL+'/api/collections/federations/records/'+id, headers:pbH, json:true });
const override = fed.gate_override || 'default';
let eff = gate;
if (override === 'always_review') eff = 'review_all';
else if (override === 'always_auto') eff = 'auto_all';

let route = 'review';
if (discover.ok) {
  if (eff === 'review_all') route = 'review';
  else { const auto = (eff === 'auto_all' || eff === 'auto_safe'); const methods = (Array.isArray(fed.directory_urls)?fed.directory_urls:[]).map(d => d && d.extraction_method);
    if (methods.includes('pdf')) route = auto ? 'extract_pdf' : 'review';   // a PDF member list is the authoritative, complete source -> dedicated PDF extractor
    else if (method === 'api_endpoint') route = 'extract_api';
    else if (method === 'js') route = auto ? 'extract_api' : 'review';
    else if (method === 'static') route = auto ? 'extract_html' : 'review';
    else route = 'review'; }
}

let extract = null;
if (route === 'extract_api') {
  extract = await this.helpers.httpRequest({ method:'POST', url: cfg.extractApiUrl, body:{ id }, json:true });
  const got = (extract && ((extract.created||0)+(extract.updated||0))) || 0;
  if (got === 0 && method !== 'api_endpoint') {   // embedded-JSON found no usable array on a js page -> Firecrawl+LLM fallback
    const html = await this.helpers.httpRequest({ method:'POST', url: cfg.extractHtmlUrl, body:{ id }, json:true });
    extract = { route:'extract_api->html_fallback', api:extract, html }; route = 'extract_api+html';
  }
} else if (route === 'extract_html') extract = await this.helpers.httpRequest({ method:'POST', url: cfg.extractHtmlUrl, body:{ id }, json:true });
else if (route === 'extract_pdf') extract = await this.helpers.httpRequest({ method:'POST', url: cfg.extractPdfUrl, body:{ id }, json:true });

return [{ json: { id, federation: discover.federation, gate: eff, method, route,
  discover: { ok: discover.ok, primary: discover.primary_directory_url, confidence: discover.confidence },
  extract } }];
